async (params, browser) => {
  // Open Medium trending page
  await browser.open('https://medium.com/explore/topics/popular')

  // Wait for trending page to load
  await browser.waitForSelector('article, [data-testid=\'postPreview\'], div[class*=\'postArticle\'], h2', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(1500)

  // Extract trending articles
  const trending_data = await browser.evaluate(`const articles = []; const articleEls = document.querySelectorAll('article, [data-testid="postPreview"], div[class*="postArticle"]'); for (let i = 0; i < Math.min(articleEls.length, 20); i++) { const el = articleEls[i]; const titleEl = el.querySelector('h2, h3, [class*="title"]'); const authorEl = el.querySelector('a[data-testid="authorName"], a[rel="author"], [class*="author"] a'); const pubEl = el.querySelector('[class*="publication"] a, a[data-testid="publicationName"]'); const clapsEl = el.querySelector('[class*="clap"] span, button[data-testid="clap"] span'); const dateEl = el.querySelector('time, span[class*="date"]'); const readTimeEl = el.querySelector('[class*="readingTime"], span[class*="read-time"]'); const linkEl = el.querySelector('a[href*="/p/"], h2 a, h3 a'); const imgEl = el.querySelector('img[src*="miro.medium"], img[loading]'); articles.push({ rank: i + 1, title: titleEl ? titleEl.textContent.trim() : '', author: authorEl ? authorEl.textContent.trim() : '', publication: pubEl ? pubEl.textContent.trim() : '', claps: clapsEl ? clapsEl.textContent.trim() : '', date: dateEl ? (dateEl.getAttribute('datetime') || dateEl.textContent.trim()) : '', read_time: readTimeEl ? readTimeEl.textContent.trim() : '', url: linkEl ? linkEl.href : '', image: imgEl ? imgEl.getAttribute('src') : '' }); } return { trending_count: articles.length, articles: articles, url: window.location.href }`)

  return trending_data
}
